public class Tier {
    String name;
    void lautGeben() {
        System.out.println(name + " macht ein Geräusch");
    }
}

class Hund extends Tier {
    // erbt name und lautGeben()
}

class Hund extends Tier {
    @Override
    void lautGeben() {
        System.out.println(name + " bellt: Wuff!");
    }
}

void untersuchen(Tier t) {
    t.lautGeben();   // funktioniert für JEDE Tier-Unterklasse
}

abstract class Tier {
    String name;
    abstract void lautGeben();   // kein Rumpf — jede Unterklasse MUSS das liefern
}

class Hund extends Tier {
    void lautGeben() { System.out.println(name + " bellt"); }
}

interface Fahrbar {
    void fahren();   // automatisch public, kein Rumpf erlaubt
}

class Auto implements Fahrbar {
    public void fahren() { System.out.println("Auto fährt"); }
}

class Fahrrad implements Fahrbar {
    public void fahren() { System.out.println("Fahrrad fährt"); }
}

Fahrbar[] fahrzeuge = { new Auto(), new Fahrrad() };
for (Fahrbar f : fahrzeuge) {
    f.fahren();   // Polymorphie über das Interface, nicht über eine Oberklasse
}

