public class Konto {
    double stand;

    void einzahlen(double betrag) {
        stand = stand + betrag;
    }
}

void abheben(double betrag) {
    if (betrag <= stand) {
        stand = stand - betrag;
        System.out.println("Abgehoben: " + betrag + ", Stand: " + stand);
    } else {
        System.out.println("Nicht genug Guthaben");
    }
}

class Sparkonto extends Konto {
    void verzinsen(double satz) {
        stand = stand + stand * satz / 100;
    }
}

