int[] zahlen = { 4, 8, 15, 16, 23, 42 };
System.out.println(zahlen[0]);       // 4
System.out.println(zahlen.length);   // 6

int summe = 0;
for (int i = 0; i < zahlen.length; i++) {
    summe += zahlen[i];
}

int gesucht = 16;
int index = -1;
for (int i = 0; i < zahlen.length; i++) {
    if (zahlen[i] == gesucht) {
        index = i;
        break;
    }
}

int lo = 0, hi = zahlen.length - 1, index = -1;
while (lo <= hi) {
    int mitte = (lo + hi) / 2;
    if (zahlen[mitte] == gesucht) { index = mitte; break; }
    else if (zahlen[mitte] < gesucht) lo = mitte + 1;   // rechte Hälfte
    else hi = mitte - 1;                                 // linke Hälfte
}

for (int i = 0; i < zahlen.length - 1; i++) {
    for (int j = 0; j < zahlen.length - 1 - i; j++) {
        if (zahlen[j] > zahlen[j + 1]) {
            int tmp = zahlen[j];
            zahlen[j] = zahlen[j + 1];
            zahlen[j + 1] = tmp;
        }
    }
}

for (int i = 1; i < zahlen.length; i++) {
    int akt = zahlen[i];
    int j = i - 1;
    while (j >= 0 && zahlen[j] > akt) {
        zahlen[j + 1] = zahlen[j];   // nach rechts schieben
        j--;
    }
    zahlen[j + 1] = akt;             // akt an die freie Stelle
}

for (int i = 0; i < zahlen.length - 1; i++) {
    int minIndex = i;
    for (int j = i + 1; j < zahlen.length; j++) {
        if (zahlen[j] < zahlen[minIndex]) minIndex = j;
    }
    int tmp = zahlen[i];
    zahlen[i] = zahlen[minIndex];
    zahlen[minIndex] = tmp;
}

void quicksort(int[] z, int lo, int hi) {
    if (lo >= hi) return;              // Basisfall: 0 oder 1 Element
    int pivot = z[hi];
    int i = lo - 1;
    for (int j = lo; j < hi; j++) {
        if (z[j] < pivot) { i++; tausche(z, i, j); }
    }
    tausche(z, i + 1, hi);
    int p = i + 1;                     // Position des Pivots nach dem Partitionieren
    quicksort(z, lo, p - 1);           // rekursiv: linke Hälfte
    quicksort(z, p + 1, hi);           // rekursiv: rechte Hälfte
}

int[] mergeSort(int[] z) {
    if (z.length <= 1) return z;                    // Basisfall
    int mitte = z.length / 2;
    int[] links  = mergeSort(Arrays.copyOfRange(z, 0, mitte));
    int[] rechts = mergeSort(Arrays.copyOfRange(z, mitte, z.length));
    return verschmelzen(links, rechts);
}

int[] verschmelzen(int[] links, int[] rechts) {
    int[] ergebnis = new int[links.length + rechts.length];
    int i = 0, j = 0, k = 0;
    while (i < links.length && j < rechts.length) {
        ergebnis[k++] = (links[i] <= rechts[j]) ? links[i++] : rechts[j++];
    }
    while (i < links.length)  ergebnis[k++] = links[i++];   // Reste anhängen
    while (j < rechts.length) ergebnis[k++] = rechts[j++];
    return ergebnis;
}

