    }

    String entfernen() {
        String wert = kopf.wert;
        kopf = kopf.next;                       // vorne entfernen
        if (kopf == null) ende = null;          // Schlange jetzt leer
        return wert;
    }

    boolean istLeer() { return kopf == null; }
}

