try {
    int ergebnis = 10 / 0;   // wirft ArithmeticException
    System.out.println(ergebnis);
} catch (ArithmeticException e) {
    System.out.println("Fehler: Division durch Null");
}
System.out.println("Das Programm läuft weiter!");

try {
    System.out.println("Versuch...");
    throw new RuntimeException("Kaputt");
} catch (RuntimeException e) {
    System.out.println("Gefangen: " + e.getMessage());
} finally {
    System.out.println("Läuft immer");
}

static int teilen(int a, int b) {
    if (b == 0) {
        throw new IllegalArgumentException("Divisor darf nicht 0 sein");
    }
    return a / b;
}

