import java.io.*;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) throws Exception {
        int n = new Scanner(System.in).nextInt();
        BufferedWriter bw = new BufferedWriter(new FileWriter("liste.txt"));
        for (int i = 1; i <= n; i++) {
            bw.write("Zeile " + i);
            bw.newLine();
        }
        bw.close();

        BufferedReader br = new BufferedReader(new FileReader("liste.txt"));
        int anzahl = 0;
        while (br.readLine() != null) anzahl++;
        br.close();
        System.out.println("Zeilenanzahl: " + anzahl);
    }
}

