import java.util.*;

public class Main {
    static List<Map<String,String>> tabelle = new ArrayList<>();
    static void insert(String name, String stadt) {
        Map<String,String> zeile = new HashMap<>();
        zeile.put("name", name);
        zeile.put("stadt", stadt);
        tabelle.add(zeile);
    }
    static int selectWhereStadt(String stadt) {
        int anzahl = 0;
        for (Map<String,String> zeile : tabelle) {
            if (zeile.get("stadt").equals(stadt)) anzahl++;
        }
        return anzahl;
    }
    public static void main(String[] args) {
        insert("Anna", "Bonn");
        insert("Ben", "Koeln");
        insert("Cem", "Bonn");
        System.out.println("Einwohner Bonn: " + selectWhereStadt("Bonn"));
    }
}

