import java.util.*;

public class Main {
    static List<Map<String,Object>> konten = new ArrayList<>();
    static void insert(String name, int guthaben) {
        Map<String,Object> zeile = new HashMap<>();
        zeile.put("name", name);
        zeile.put("guthaben", guthaben);
        konten.add(zeile);
    }
    static void updateGuthaben(String name, int neu) {
        for (Map<String,Object> zeile : konten) {
            if (zeile.get("name").equals(name)) zeile.put("guthaben", neu);
        }
    }
    static void deleteWhereName(String name) {
        konten.removeIf(zeile -> zeile.get("name").equals(name));
    }
    public static void main(String[] args) {
        insert("Anna", 100);
        insert("Ben", 50);
        updateGuthaben("Anna", 150);
        deleteWhereName("Ben");
        System.out.println("Anzahl Konten: " + konten.size());
        System.out.println("Guthaben Anna: " + konten.get(0).get("guthaben"));
    }
}

