interface Form { double flaeche(); }
class Kreis implements Form { double r; Kreis(double r){this.r=r;} public double flaeche(){return Math.PI*r*r;} }
class Quadrat implements Form { double s; Quadrat(double s){this.s=s;} public double flaeche(){return s*s;} }

static Form erzeugeForm(String typ, double groesse) {
    return switch (typ) {
        case "kreis" -> new Kreis(groesse);
        case "quadrat" -> new Quadrat(groesse);
        default -> throw new IllegalArgumentException("Unbekannt: " + typ);
    };
}

